import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    if len(unvisited_nodes) == 0:
        if current_node != depot_node:
            return depot_node
        return None

    available_nodes = [node for node in unvisited_nodes if node not in truck_nodes]

    if not available_nodes:
        return None

    shortest_loop_distance = float('inf')
    next_node = None

    for node in available_nodes:
        loop_distance = (distance_matrix[current_node, node] +
                         distance_matrix[node, depot_node] +
                         distance_matrix[depot_node, current_node])
        if loop_distance < shortest_loop_distance:
            shortest_loop_distance = loop_distance
            next_node = node

    return next_node
